def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    points = np.asarray(points, dtype=float)
    if points.ndim != 2:
        raise ValueError("points must be a 2D array of shape (N, D)")
    N, D = points.shape
    if k <= 0:
        return np.empty((0, D))
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1
    reference_point = np.asarray(reference_point, dtype=float).reshape(D)

    # Clamp points to reference (boxes beyond reference have zero width in that dimension)
    pts = np.minimum(points, reference_point)

    def filter_nondominated(X):
        # Minimization Pareto front: keep points that are not dominated by any other (q <= p)
        if X.size == 0:
            return X.reshape(0, D)
        X = np.asarray(X)
        idx = np.argsort(X[:, 0], kind='mergesort')
        Xs = X[idx]
        keep = []
        for p in Xs:
            dominated = False
            for q in keep:
                if np.all(q <= p):
                    dominated = True
                    break
            if not dominated:
                # remove any kept points dominated by p
                new_keep = []
                for q in keep:
                    if not np.all(p <= q):
                        new_keep.append(q)
                new_keep.append(p)
                keep = new_keep
        if len(keep) == 0:
            return X.reshape(0, D)
        return np.vstack(keep)

    # Recursive WFG-style hypervolume of union of axis-aligned boxes [p, ref]
    def hypervolume(X, ref):
        X = np.asarray(X, dtype=float)
        if X.size == 0:
            return 0.0
        # clamp to ref
        X = np.minimum(X, ref)
        # filter dominated points to reduce work
        X = filter_nondominated(X)
        if X.size == 0:
            return 0.0
        m, d = X.shape
        if d == 1:
            minv = np.min(X[:, 0])
            return max(0.0, ref[0] - minv)
        # sort by last coordinate ascending
        idx = np.argsort(X[:, -1], kind='mergesort')
        Xs = X[idx]
        hv = 0.0
        current = ref[-1]
        # iterate from largest last-coordinate to smallest
        for i in range(m - 1, -1, -1):
            py = Xs[i, -1]
            if py < current:
                # subset of points that reach at least py (i..m-1)
                subset = Xs[i:, :d-1]
                slice_height = current - py
                if subset.size > 0 and slice_height > 0:
                    hv_slice = hypervolume(subset, ref[:d-1])
                    hv += slice_height * hv_slice
                current = py
        return hv

    # Pre-filter global dominated points
    pts = filter_nondominated(pts)
    M = pts.shape[0]
    if M == 0:
        return np.empty((0, D))
    if k >= M:
        # return all non-dominated points (clipped)
        return pts[:k] if k <= M else np.vstack([pts, np.tile(reference_point, (k - M, 1))])

    selected = []
    sel_mask = np.zeros(M, dtype=bool)
    current_selected = np.empty((0, D))
    current_hv = 0.0

    # Precompute hv of single points to speed up initial selection
    single_hvs = np.empty(M)
    for i in range(M):
        single_hvs[i] = hypervolume(pts[i:i+1, :], reference_point)
    # Greedy selection
    for _ in range(min(k, M)):
        best_idx = -1
        best_gain = -np.inf
        # For each unselected point compute marginal gain
        for i in range(M):
            if sel_mask[i]:
                continue
            candidate_set = np.vstack([current_selected, pts[i:i+1, :]]) if current_selected.size else pts[i:i+1, :]
            hv_with = hypervolume(candidate_set, reference_point)
            gain = hv_with - current_hv
            # small numerical tolerance
            if gain > best_gain + 1e-12:
                best_gain = gain
                best_idx = i
        if best_idx < 0:
            break
        # add best
        sel_mask[best_idx] = True
        if current_selected.size == 0:
            current_selected = pts[best_idx:best_idx+1, :].copy()
        else:
            current_selected = np.vstack([current_selected, pts[best_idx:best_idx+1, :]])
        current_hv += max(0.0, best_gain)
        selected.append(best_idx)

    # Return selected points (clipped to reference)
    selected_points = pts[selected, :]
    # If fewer than k selected due to degeneracy, pad with remaining best single-hv points
    if selected_points.shape[0] < k:
        remaining = [i for i in range(M) if i not in selected]
        if remaining:
            remaining = sorted(remaining, key=lambda i: -single_hvs[i])
            need = k - selected_points.shape[0]
            add_idx = remaining[:need]
            if selected_points.size == 0:
                selected_points = pts[add_idx, :]
            else:
                selected_points = np.vstack([selected_points, pts[add_idx, :]])
    return np.array(selected_points[:k], dtype=float)

def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    if not isinstance(points, np.ndarray):
        points = np.array(points, dtype=float)
    else:
        points = points.astype(float, copy=False)

    n, m = points.shape
    if k <= 0 or k > n:
        raise ValueError("k must be > 0 and <= number of points")

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1
    reference_point = np.array(reference_point, dtype=float)

    # Dominance: p dominates q if all coords >= and at least one >
    def dominates(p, q):
        return np.all(p >= q) and np.any(p > q)

    # Pareto filter: return indices of non-dominated points among given indices
    def pareto_filter(idx_list):
        if len(idx_list) == 0:
            return np.array([], dtype=int)
        arr = points[idx_list]
        keep_mask = np.ones(len(idx_list), dtype=bool)
        for i in range(len(idx_list)):
            if not keep_mask[i]:
                continue
            # any point that dominates arr[i] -> mark arr[i] as not keep
            # check others j != i
            comp = arr >= arr[i]  # shape (len, m)
            all_ge = np.all(comp, axis=1)
            any_gt = np.any(arr > arr[i], axis=1)
            dominates_i = all_ge & any_gt
            # if any j dominates i (i.e., dominates_i[j]==True for some j != i), then remove i
            if np.any(dominates_i & (np.arange(len(idx_list)) != i)):
                keep_mask[i] = False
        return np.array(idx_list)[keep_mask]

    # Helper: check if candidate index is dominated by any of the selected points
    def is_dominated_by_selected(idx, selected_idx_list):
        if len(selected_idx_list) == 0:
            return False
        p = points[idx]
        sel = points[selected_idx_list]
        # check if any selected point dominates p
        ge = sel >= p  # (s, m)
        all_ge = np.all(ge, axis=1)
        any_gt = np.any(sel > p, axis=1)
        return np.any(all_ge & any_gt)

    # Precompute individual hypervolumes (could be used to break ties / fill)
    indiv_hv = np.zeros(n)
    for i in range(n):
        try:
            indiv_hv[i] = pg.hypervolume(points[[i]]).compute(reference_point)
        except Exception:
            indiv_hv[i] = 0.0

    candidate_indices = list(range(n))
    selected_indices = []
    current_hv = 0.0
    selected_points = np.empty((0, m), dtype=float)

    for _ in range(k):
        if len(candidate_indices) == 0:
            break

        # Pareto-prune candidates to speed up: only consider non-dominated among remaining
        candidate_indices = list(pareto_filter(candidate_indices))

        best_idx = None
        best_gain = -np.inf

        # For each candidate, skip if already dominated by selected set (contribution zero)
        for idx in candidate_indices:
            if is_dominated_by_selected(idx, selected_indices):
                # zero contribution, but still might be needed later for tie-breaking; skip heavy calc
                continue
            # compute hv with this candidate added
            if selected_points.size == 0:
                try:
                    new_hv = pg.hypervolume(points[[idx]]).compute(reference_point)
                except Exception:
                    new_hv = 0.0
            else:
                try:
                    new_hv = pg.hypervolume(np.vstack([selected_points, points[[idx]]])).compute(reference_point)
                except Exception:
                    new_hv = 0.0
            gain = new_hv - current_hv
            if gain > best_gain:
                best_gain = gain
                best_idx = idx

        # If no positive-gain candidate found (or all skipped), pick the remaining candidate with largest individual hv
        if best_idx is None:
            # fallback: pick highest individual hv among candidates not yet selected
            remaining = [i for i in candidate_indices if i not in selected_indices]
            if len(remaining) == 0:
                break
            best_idx = int(remaining[np.argmax(indiv_hv[remaining])])
            # compute its gain for updating hv
            if selected_points.size == 0:
                try:
                    new_hv = pg.hypervolume(points[[best_idx]]).compute(reference_point)
                except Exception:
                    new_hv = 0.0
            else:
                try:
                    new_hv = pg.hypervolume(np.vstack([selected_points, points[[best_idx]]])).compute(reference_point)
                except Exception:
                    new_hv = 0.0
            best_gain = new_hv - current_hv

        # Add chosen point
        selected_indices.append(int(best_idx))
        if selected_points.size == 0:
            selected_points = points[[best_idx]].copy()
        else:
            selected_points = np.vstack([selected_points, points[[best_idx]]])
        current_hv += max(0.0, best_gain)  # ensure non-decreasing

        # remove chosen from candidates
        if best_idx in candidate_indices:
            candidate_indices.remove(best_idx)
        # also remove any points that are now dominated by the newly selected point (pruning)
        to_remove = []
        for idx in list(candidate_indices):
            if dominates(points[best_idx], points[idx]):
                to_remove.append(idx)
        for idx in to_remove:
            if idx in candidate_indices:
                candidate_indices.remove(idx)

    # If for some reason fewer than k selected (e.g., duplicates), fill with highest individual hv among remaining
    if len(selected_indices) < k:
        remaining = [i for i in range(n) if i not in selected_indices]
        if len(remaining) > 0:
            sorted_by_indiv = sorted(remaining, key=lambda i: indiv_hv[i], reverse=True)
            need = k - len(selected_indices)
            selected_indices.extend(sorted_by_indiv[:need])

    # Final guard: ensure exactly k rows returned
    selected_indices = selected_indices[:k]
    subset = points[selected_indices]
    return subset

