    # Helper: check if candidate index is dominated by any of the selected points
    def is_dominated_by_selected(idx, selected_idx_list):
        if len(selected_idx_list) == 0:
            return False
        p = points[idx]
        sel = points[selected_idx_list]
        # check if any selected point dominates p
        ge = sel >= p  # (s, m)
        all_ge = np.all(ge, axis=1)
        any_gt = np.any(sel > p, axis=1)
        return np.any(all_ge & any_gt)

    # Precompute individual hypervolumes (could be used to break ties / fill)
    indiv_hv = np.zeros(n)
    for i in range(n):
        try:
            indiv_hv[i] = pg.hypervolume(points[[i]]).compute(reference_point)
        except Exception:
            indiv_hv[i] = 0.0

