    selected_indices = []
    current_hv = 0.0
    selected_points = np.empty((0, m), dtype=float)

    for _ in range(k):
        if len(candidate_indices) == 0:
            break

        # Pareto-prune candidates to speed up: only consider non-dominated among remaining
        candidate_indices = list(pareto_filter(candidate_indices))

        best_idx = None
        best_gain = -np.inf

        # For each candidate, skip if already dominated by selected set (contribution zero)
        for idx in candidate_indices:
